import{_ as t,o as a,c as s,ag as n}from"./chunks/framework.DFmy_ALI.js";const k=JSON.parse('{"title":"OpenWave OAuth Gateway","description":"","frontmatter":{},"headers":[],"relativePath":"guide/openwave-oauth-gateway.md","filePath":"guide/openwave-oauth-gateway.md"}'),i={name:"guide/openwave-oauth-gateway.md"};function o(r,e,d,l,p,c){return a(),s("div",null,[...e[0]||(e[0]=[n(`<h1 id="openwave-oauth-gateway" tabindex="-1">OpenWave OAuth Gateway <a class="header-anchor" href="#openwave-oauth-gateway" aria-label="Permalink to &quot;OpenWave OAuth Gateway&quot;">​</a></h1><p>OpenWave OAuth is the scoped access layer for Astro, OpenWave Identity, Remote MCP, and future fintech apps.</p><p>OpenWave Identity issues tokens. Astro and Remote MCP validate those tokens as protected resources. Existing merchant keys, bank keys, and portal sessions remain supported.</p><h2 id="token-issuer" tabindex="-1">Token issuer <a class="header-anchor" href="#token-issuer" aria-label="Permalink to &quot;Token issuer&quot;">​</a></h2><p>OpenWave Identity owns:</p><ul><li>OAuth client registry.</li><li>client credentials.</li><li>token issuance.</li><li>token introspection and revocation.</li><li>global kill switches.</li><li>user/client grant revocation.</li></ul><p>Astro does not issue OpenWave ecosystem OAuth tokens.</p><h2 id="v1-grants" tabindex="-1">V1 grants <a class="header-anchor" href="#v1-grants" aria-label="Permalink to &quot;V1 grants&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Grant</th><th>Use</th></tr></thead><tbody><tr><td><code>client_credentials</code></td><td>Merchant backends, bank middleware, Neptune services, MCP clients.</td></tr><tr><td><code>refresh_token</code></td><td>Rotates delegated access tokens.</td></tr><tr><td><code>authorization_code</code> + PKCE</td><td>Reserved for delegated customer/operator UI rollout.</td></tr></tbody></table><h2 id="token-endpoint" tabindex="-1">Token endpoint <a class="header-anchor" href="#token-endpoint" aria-label="Permalink to &quot;Token endpoint&quot;">​</a></h2><div class="language-http vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">http</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">POST</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /v1/oauth/token</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">Content-Type</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> application/x-www-form-urlencoded</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">grant_type=client_credentials&amp;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">client_id=owc_...&amp;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">client_secret=ows_...&amp;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">scope=astro:merchant.reports.read openwave:mcp.read&amp;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">audience=astro&amp;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">environment=SANDBOX</span></span></code></pre></div><p>The response contains a bearer access token and refresh token. Keep both server-side.</p><h2 id="astro-resource-access" tabindex="-1">Astro resource access <a class="header-anchor" href="#astro-resource-access" aria-label="Permalink to &quot;Astro resource access&quot;">​</a></h2><div class="language-http vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">http</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">GET</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /api/v1/merchant/integration</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">Authorization</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Bearer owat_...</span></span></code></pre></div><p>Astro accepts Identity-issued OAuth tokens only when:</p><ul><li>OAuth is enabled.</li><li>the token is active by Identity introspection.</li><li>the client is active.</li><li>the token environment is enabled.</li><li>the owner type is enabled.</li><li>the required scope is present.</li><li>the tenant in the token matches the requested resource.</li></ul><h2 id="recommended-scopes" tabindex="-1">Recommended scopes <a class="header-anchor" href="#recommended-scopes" aria-label="Permalink to &quot;Recommended scopes&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Scope</th><th>Purpose</th></tr></thead><tbody><tr><td><code>astro:payments.create</code></td><td>Create payment sessions.</td></tr><tr><td><code>astro:payments.read</code></td><td>Read payment/session status.</td></tr><tr><td><code>astro:merchant.reports.read</code></td><td>Merchant-scoped reports.</td></tr><tr><td><code>astro:merchant.webhooks.manage</code></td><td>Merchant webhook management.</td></tr><tr><td><code>astro:bank.reports.read</code></td><td>Bank-scoped reports.</td></tr><tr><td><code>openwave:mcp.read</code></td><td>Remote MCP read tools.</td></tr><tr><td><code>openwave:mcp.write</code></td><td>Remote MCP write tools, still blocked unless mutation switch is enabled.</td></tr><tr><td><code>openwave:owner.ops.read</code></td><td>Neptune owner operations overview and incident reports.</td></tr></tbody></table><h2 id="backward-compatibility" tabindex="-1">Backward compatibility <a class="header-anchor" href="#backward-compatibility" aria-label="Permalink to &quot;Backward compatibility&quot;">​</a></h2><p>Existing raw merchant keys and bank keys are not removed. OAuth is additive so partners can migrate without breaking current integrations.</p>`,20)])])}const u=t(i,[["render",o]]);export{k as __pageData,u as default};
